const api = $input.item.json;
// Fallback al id de la BD para que enrich_tried_at se marque siempre,
// incluso cuando la API de Flexicar devuelve error (404, timeout, etc.)
const dbId = String($('Loop: oferta por oferta').item.json.id || '');
const id = api.id ? String(api.id) : dbId;

if (!id) {
  await new Promise(r => setTimeout(r, 800));
  return [{ json: { id: null, hasUpdates: false, updateSql: null } }];
}

function esc(v) {
  if (v === null || v === undefined) return "NULL";
  if (typeof v === "number") return isNaN(v) ? "NULL" : String(v);
  return "'" + String(v).replace(/'/g, "''") + "'";
}

function normalizeBody(raw) {
  const s = String(raw || "").toLowerCase();
  if (s.indexOf("suv") !== -1 || s.indexOf("4x4") !== -1 || s.indexOf("todoterreno") !== -1) return "SUV";
  if (s.indexOf("berlina") !== -1 || s.indexOf("sedan") !== -1) return "Berlina";
  if (s.indexOf("familiar") !== -1 || s.indexOf("estate") !== -1) return "Familiar";
  if (s.indexOf("coupe") !== -1 || s.indexOf("coupé") !== -1) return "Coupé";
  if (s.indexOf("cabrio") !== -1 || s.indexOf("convert") !== -1) return "Cabrio";
  if (s.indexOf("monovolumen") !== -1 || s.indexOf("mpv") !== -1) return "Monovolumen";
  if (s.indexOf("hatchback") !== -1) return "Berlina";
  return raw || "";
}

const sets = [];

if (api.color) sets.push("color = COALESCE(NULLIF(color,''), " + esc(api.color) + ")");
if (api.doors) sets.push("doors = COALESCE(NULLIF(doors,0), " + api.doors + ")");
if (api.seats) sets.push("seats = COALESCE(NULLIF(seats,0), " + api.seats + ")");
if (api.hp) sets.push("power_cv = COALESCE(NULLIF(power_cv,0), " + api.hp + ")");
if (api.cylinder) sets.push("displacement = COALESCE(NULLIF(displacement,''), '" + Math.round(api.cylinder * 1000) + "')");
if (api.mixedConsumption != null && api.mixedConsumption > 0) {
  sets.push("consumption = COALESCE(NULLIF(consumption,0), " + api.mixedConsumption + ")");
}
if (api.body) sets.push("body_type = COALESCE(NULLIF(body_type,''), " + esc(normalizeBody(api.body)) + ")");
if (Array.isArray(api.images) && api.images.length > 0) {
  const imgUrls = api.images.map(function(i) { return i.image || ""; }).filter(Boolean).slice(0, 20);
  if (imgUrls.length > 0) {
    sets.push("image_url = COALESCE(NULLIF(image_url,''), " + esc(imgUrls[0]) + ")");
    sets.push("images = COALESCE(NULLIF(images,''), " + esc(JSON.stringify(imgUrls)) + ")");
  }
}
if (Array.isArray(api.dataSheet)) {
  const ds = api.dataSheet.join(" ").toLowerCase();
  if (ds.indexOf("tracción total") !== -1 || ds.indexOf("tracción integral") !== -1 || ds.indexOf("tracción 4x4") !== -1) {
    sets.push("traction = COALESCE(NULLIF(traction,''), '4x4')");
  } else if (ds.indexOf("tracción trasera") !== -1) {
    sets.push("traction = COALESCE(NULLIF(traction,''), 'Trasera')");
  } else if (ds.indexOf("tracción delantera") !== -1) {
    sets.push("traction = COALESCE(NULLIF(traction,''), 'Delantera')");
  }
  const dsText = api.dataSheet.join(" ");
  const wltpIdx = dsText.toLowerCase().indexOf("emisiones wltp ice");
  if (wltpIdx !== -1) {
    const after = dsText.slice(wltpIdx + 18, wltpIdx + 60);
    const m = after.match(/(\d+)/);
    if (m) sets.push("co2 = COALESCE(NULLIF(co2,''), '" + m[1] + "')");
  }
}

// Siempre marcar enrich_tried_at, incluso si la API no devolvió datos útiles
sets.push("enrich_tried_at = NOW()");

const updateSql = "UPDATE moveadvisor_market_offers SET " + sets.join(", ") + ", updated_at = NOW() WHERE id = '" + id.replace(/'/g, "''") + "'";

// Rate limit sin nodo Wait (que bloquea el loop con webhooks internos)
await new Promise(r => setTimeout(r, 800));

return [{ json: { id: id, hasUpdates: true, updateSql: updateSql } }];
